LAYER
	NAME "manzana"
	TYPE polygon
	STATUS on
	DATA "geom FROM (SELECT gid, id_ubigeo, cod_sector, id_sector, cod_mzna, id_mzna, area_grafi, peri_grafi, geom FROM geo.tg_manzana) as kaypacha using unique gid using srid=32719"
	INCLUDE "configuracion/postgresql_allpa.map"
	CLASSITEM "gid"
	PROJECTION
	"init=epsg:32719"
	END
	METADATA
		"layer_encoding" "Latin1"
		"wfs_encoding" "Latin1"
		"queryable" "true"
		"wfs_abstract" "Manzana || Municipalidad Provincial de Espinar - Cusco :: Perú"
		"wfs_title" "Manzana"
		"wfs_credit" "MPE"
		"wfs_srs" "EPSG:32719"
		"gml_include_items" "all"
		"gml_featureid" "gid"
		"wfs_getfeature_formatlist" "OGRGML,SHAPE-ZIP,CSV,geojson"
		#"wfs_additional_files_in_output" "lotes.pdf,lotes.lyr"
	END
	CLASS
		NAME "Manzana"
		STYLE
			COLOR -1 -1 -1
			OUTLINECOLOR 100 107 99
			WIDTH 1
		END
	END
END # Layer